 96→// ---------------------------------------------------------------------------
 97→// FastDdsSubscriptionManager
 98→// ---------------------------------------------------------------------------
 99→FastDdsSubscriptionManager::FastDdsSubscriptionManager(FastDdsTopicSource& topic_source)
100→    : topic_source_(topic_source) {}
101→
102→FastDdsSubscriptionManager::~FastDdsSubscriptionManager() {
103→  unsubscribe_all();
104→}
