182→bool FastDdsSubscriptionManager::unsubscribe(const std::string& topic_name) {
183→  SubscriptionInfo to_close{};
184→  bool should_close = false;
185→
186→  {
187→    std::lock_guard<std::mutex> lock(mutex_);
188→
189→    auto it = subscriptions_.find(topic_name);
190→    if (it == subscriptions_.end()) {
191→      return false;
192→    }
193→
194→    if (it->second.reference_count == 0) {
195→      return false;
196→    }
197→
198→    it->second.reference_count--;
199→    spdlog::debug("Decremented ref count for '{}' to {}", topic_name, it->second.reference_count);
200→
201→    if (it->second.reference_count == 0) {
202→      to_close = std::move(it->second);
203→      should_close = true;
204→      subscriptions_.erase(it);
205→    }
206→  }
207→
208→  // Close DDS entities outside lock to avoid deadlock
209→  if (should_close) {
210→    close_subscription(topic_name, to_close);
211→    spdlog::info("Unsubscribed from '{}' (reader destroyed)", topic_name);
212→  }
213→
214→  return true;
215→}
