 26→GenericSubscriptionManager::GenericSubscriptionManager(rclcpp::Node::SharedPtr node) : node_(node) {}
 27→
 28→bool GenericSubscriptionManager::subscribe(
 29→    const std::string& topic_name, const std::string& topic_type, Ros2MessageCallback callback) {
 30→  std::lock_guard<std::mutex> lock(mutex_);
 31→
 32→  auto it = subscriptions_.find(topic_name);
 33→
 34→  if (it != subscriptions_.end()) {
 35→    it->second.reference_count++;
 36→    return true;
 37→  }
 38→
 39→  try {
 40→    auto sub_callback = [topic_name, callback](std::shared_ptr<rclcpp::SerializedMessage> msg) {
 41→      uint64_t receive_time = get_current_time_ns();
 42→      callback(topic_name, msg, receive_time);
 43→    };
 44→
 45→    auto subscription = node_->create_generic_subscription(topic_name, topic_type, rclcpp::QoS(100), sub_callback);
 46→
 47→    subscriptions_[topic_name] = SubscriptionInfo{subscription, 1};
 48→
 49→    return true;
 50→  } catch (const std::exception& e) {
 51→    RCLCPP_ERROR(
 52→        node_->get_logger(), "Failed to create subscription for topic '%s' (type '%s'): %s", topic_name.c_str(),
 53→        topic_type.c_str(), e.what());
 54→    return false;
 55→  }
 56→}
 57→
 58→bool GenericSubscriptionManager::unsubscribe(const std::string& topic_name) {
 59→  std::lock_guard<std::mutex> lock(mutex_);
 60→
 61→  auto it = subscriptions_.find(topic_name);
 62→  if (it == subscriptions_.end()) {
 63→    return false;
 64→  }
 65→
 66→  if (it->second.reference_count == 0) {
 67→    return false;
 68→  }
 69→
 70→  it->second.reference_count--;
 71→
 72→  if (it->second.reference_count == 0) {
 73→    subscriptions_.erase(it);
 74→  }
 75→
 76→  return true;
 77→}
 78→
 79→bool GenericSubscriptionManager::is_subscribed(const std::string& topic_name) const {
 80→  std::lock_guard<std::mutex> lock(mutex_);
 81→  return subscriptions_.find(topic_name) != subscriptions_.end();
 82→}
 83→
 84→size_t GenericSubscriptionManager::get_reference_count(const std::string& topic_name) const {
 85→  std::lock_guard<std::mutex> lock(mutex_);
 86→
 87→  auto it = subscriptions_.find(topic_name);
 88→  if (it != subscriptions_.end()) {
 89→    return it->second.reference_count;
 90→  }
 91→
 92→  return 0;
 93→}
 94→
 95→void GenericSubscriptionManager::unsubscribe_all() {
 96→  std::lock_guard<std::mutex> lock(mutex_);
 97→  subscriptions_.clear();
 98→}
