31→int main(int argc, char* argv[]) {
32→  CLI::App app{"pj_bridge RTI DDS Backend"};
33→
34→  std::vector<int32_t> domain_ids;
35→  int port = 8080;
36→  double publish_rate = 50.0;
37→  double session_timeout = 10.0;
38→  std::string qos_profile;
39→  std::string log_level = "info";
40→  bool stats_enabled = false;
41→
42→  app.add_option("--domains,-d", domain_ids, "DDS domain IDs")->required()->expected(1, -1);
43→  app.add_option("--port,-p", port, "WebSocket port")->default_val(8080)->check(CLI::Range(1, 65535));
44→  app.add_option("--publish-rate", publish_rate, "Aggregation publish rate in Hz")->default_val(50.0);
45→  app.add_option("--session-timeout", session_timeout, "Session timeout in seconds")->default_val(10.0);
46→  app.add_option("--qos-profile", qos_profile, "QoS profile XML file path");
47→  app.add_option("--log-level", log_level, "Log level (trace, debug, info, warn, error)")->default_val("info");
48→  app.add_flag("--stats", stats_enabled, "Print statistics every 5 seconds");
49→
50→  CLI11_PARSE(app, argc, argv);
51→
52→  spdlog::set_level(spdlog::level::from_str(log_level));
53→
54→  spdlog::info("pj_bridge (RTI DDS backend) starting...");
55→  spdlog::info("  Domains: {}", fmt::join(domain_ids, ", "));
56→  spdlog::info("  Port: {}", port);
57→  spdlog::info("  Publish rate: {:.1f} Hz", publish_rate);
58→  spdlog::info("  Session timeout: {:.1f} s", session_timeout);
59→  if (!qos_profile.empty()) {
60→    spdlog::info("  QoS profile: {}", qos_profile);
61→  }
62→
63→  try {
64→    auto topic_source = std::make_shared<pj_bridge::DdsTopicDiscovery>(domain_ids, qos_profile);
65→    auto sub_manager = std::make_shared<pj_bridge::DdsSubscriptionManager>(*topic_source);
66→    auto middleware = std::make_shared<pj_bridge::WebSocketMiddleware>();
67→
68→    pj_bridge::BridgeServer server(topic_source, sub_manager, middleware, port, session_timeout, publish_rate);
69→
70→    pj_bridge::run_standalone_event_loop(
71→        server, sub_manager, middleware, {port, publish_rate, session_timeout, stats_enabled});
72→  } catch (const std::exception& e) {
73→    spdlog::error("Fatal error: {}", e.what());
74→    return 1;
75→  }
76→
77→  return 0;
78→}
