24→TopicDiscovery::TopicDiscovery(rclcpp::Node::SharedPtr node) : node_(node) {}
25→
26→std::vector<TopicInfo> TopicDiscovery::discover_topics() {
27→  topics_.clear();
28→
29→  auto topic_names_and_types = node_->get_topic_names_and_types();
30→
31→  for (const auto& [topic_name, topic_types] : topic_names_and_types) {
32→    if (should_filter_topic(topic_name)) {
33→      continue;
34→    }
35→
36→    if (!topic_types.empty()) {
37→      TopicInfo info;
38→      info.name = topic_name;
39→      info.type = topic_types[0];
40→      topics_.push_back(info);
41→    }
42→  }
43→
44→  return topics_;
45→}
46→
47→std::vector<TopicInfo> TopicDiscovery::get_topics() const {
48→  return topics_;
49→}
50→
51→bool TopicDiscovery::refresh() {
52→  try {
53→    discover_topics();
54→    return true;
55→  } catch (const std::exception& e) {
56→    RCLCPP_ERROR(node_->get_logger(), "Topic discovery refresh failed: %s", e.what());
57→    return false;
58→  }
59→}
60→
61→bool TopicDiscovery::should_filter_topic(const std::string& topic_name) const {
62→  static const std::vector<std::string> kSystemTopics = {"/rosout", "/parameter_events", "/robot_description"};
63→
64→  for (const auto& system_topic : kSystemTopics) {
65→    if (topic_name == system_topic) {
66→      return true;
67→    }
68→  }
69→
70→  if (topic_name.find("/_") == 0) {
71→    return true;
72→  }
73→
74→  return false;
75→}
