 24→namespace pj_bridge {
 25→
 26→class DdsSubscriptionManager::InternalReaderListener
 27→    : public dds::sub::NoOpDataReaderListener<dds::core::xtypes::DynamicData> {
 28→ public:
 29→  InternalReaderListener(const std::string& topic_name, DdsSubscriptionManager& manager)
 30→      : topic_name_(topic_name), manager_(manager) {}
 31→
 32→  void on_data_available(dds::sub::DataReader<dds::core::xtypes::DynamicData>& reader) override {
 33→    try {
 34→      auto samples = reader.take();
 35→
 36→      MessageCallback cb;
 37→      {
 38→        std::lock_guard<std::mutex> lock(manager_.mutex_);
 39→        cb = manager_.callback_;
 40→      }
 41→
 42→      if (!cb) {
 43→        return;
 44→      }
 45→
 46→      for (const auto& sample : samples) {
 47→        if (!sample.info().valid()) {
 48→          continue;
 49→        }
 50→
 51→        auto cdr_buffer = sample.data().get_cdr_buffer();
 52→        const auto* raw_data = reinterpret_cast<const std::byte*>(cdr_buffer.first);
 53→        uint32_t data_size = cdr_buffer.second;
 54→
 55→        auto cdr_data = std::make_shared<std::vector<std::byte>>(raw_data, raw_data + data_size);
 56→
 57→        const auto& source_ts = sample.info().source_timestamp();
 58→        uint64_t timestamp_ns = (static_cast<uint64_t>(source_ts.sec()) * 1'000'000'000ULL) + source_ts.nanosec();
 59→
 60→        cb(topic_name_, std::move(cdr_data), timestamp_ns);
 61→      }
 62→    } catch (const std::exception& e) {
 63→      spdlog::error("Exception in DataReaderListener for '{}': {}", topic_name_, e.what());
 64→    }
 65→  }
 66→
 67→ private:
 68→  std::string topic_name_;
 69→  DdsSubscriptionManager& manager_;
 70→};
 71→
 72→DdsSubscriptionManager::DdsSubscriptionManager(DdsTopicDiscovery& discovery) : discovery_(discovery) {}
 73→
 74→DdsSubscriptionManager::~DdsSubscriptionManager() {
 75→  unsubscribe_all();
 76→}
 77→
 78→void DdsSubscriptionManager::set_message_callback(MessageCallback callback) {
 79→  std::lock_guard<std::mutex> lock(mutex_);
 80→  callback_ = std::move(callback);
 81→}
 82→
 83→bool DdsSubscriptionManager::subscribe(const std::string& topic_name, const std::string& /*topic_type*/) {
 84→  std::lock_guard<std::mutex> lock(mutex_);
 85→
 86→  auto it = subscriptions_.find(topic_name);
 87→  if (it != subscriptions_.end()) {
 88→    it->second.reference_count++;
 89→    spdlog::debug("Incremented ref count for '{}' to {}", topic_name, it->second.reference_count);
 90→    return true;
 91→  }
 92→
 93→  auto struct_type_opt = discovery_.get_type(topic_name);
 94→  if (!struct_type_opt) {
 95→    spdlog::error("Topic '{}' not found in discovery", topic_name);
 96→    return false;
 97→  }
 98→
 99→  auto domain_id_opt = discovery_.get_domain_id(topic_name);
100→  if (!domain_id_opt) {
101→    spdlog::error("No domain ID for topic '{}'", topic_name);
102→    return false;
103→  }
104→
105→  auto& struct_type = *struct_type_opt;
106→
107→  auto participant_opt = discovery_.get_participant(*domain_id_opt);
108→  if (!participant_opt) {
109→    spdlog::error("No participant for domain {}", *domain_id_opt);
110→    return false;
111→  }
112→
113→  try {
114→    auto& participant = *participant_opt;
115→
116→    rti::core::xtypes::DynamicDataTypeSerializationProperty ser_prop;
117→    ser_prop.skip_deserialization(true);
118→
119→    rti::domain::register_type(participant, struct_type.name(), struct_type, ser_prop);
120→
121→    dds::topic::Topic<dds::core::xtypes::DynamicData> topic(participant, topic_name, struct_type.name());
122→
123→    dds::sub::Subscriber subscriber(participant);
124→    dds::sub::DataReader<dds::core::xtypes::DynamicData> reader(subscriber, topic);
125→
126→    auto listener = std::make_shared<InternalReaderListener>(topic_name, *this);
127→    reader.set_listener(listener);
128→
129→    subscriptions_.emplace(
130→        std::piecewise_construct, std::forward_as_tuple(topic_name),
131→        std::forward_as_tuple(subscriber, reader, listener, 1));
132→
133→    spdlog::info("Subscribed to '{}' (type: '{}', domain: {})", topic_name, struct_type.name(), *domain_id_opt);
134→    return true;
135→  } catch (const std::exception& e) {
136→    spdlog::error("Failed to subscribe to '{}': {}", topic_name, e.what());
137→    return false;
138→  }
139→}
140→
141→bool DdsSubscriptionManager::unsubscribe(const std::string& topic_name) {
142→  std::optional<SubscriptionInfo> to_close;
143→
144→  {
145→    std::lock_guard<std::mutex> lock(mutex_);
146→
147→    auto it = subscriptions_.find(topic_name);
148→    if (it == subscriptions_.end()) {
149→      return false;
150→    }
151→
152→    if (it->second.reference_count == 0) {
153→      return false;
154→    }
155→
156→    it->second.reference_count--;
157→    spdlog::debug("Decremented ref count for '{}' to {}", topic_name, it->second.reference_count);
158→
159→    if (it->second.reference_count == 0) {
160→      to_close.emplace(std::move(it->second));
161→      subscriptions_.erase(it);
162→    }
163→  }
164→
165→  if (to_close) {
166→    close_reader(topic_name, *to_close);
167→    spdlog::info("Unsubscribed from '{}' (reader destroyed)", topic_name);
168→  }
169→
170→  return true;
171→}
172→
173→void DdsSubscriptionManager::unsubscribe_all() {
174→  std::unordered_map<std::string, SubscriptionInfo> to_close;
175→
176→  {
177→    std::lock_guard<std::mutex> lock(mutex_);
178→    to_close.swap(subscriptions_);
179→  }
180→
181→  spdlog::debug("[shutdown] unsubscribe_all: {} subscriptions to close", to_close.size());
182→  for (auto& [name, info] : to_close) {
183→    spdlog::debug("[shutdown] Closing reader for '{}'...", name);
184→    close_reader(name, info);
185→    spdlog::debug("[shutdown] Closed '{}'", name);
186→  }
187→  spdlog::debug("[shutdown] unsubscribe_all complete");
188→}
189→
190→void DdsSubscriptionManager::close_reader(const std::string& topic_name, SubscriptionInfo& info) {
191→  try {
192→    info.reader.set_listener(nullptr);
193→    info.reader.close();
194→    info.subscriber.close();
195→  } catch (const std::exception& e) {
196→    spdlog::warn("Error cleaning up reader for '{}': {}", topic_name, e.what());
197→  } catch (...) {
198→    spdlog::warn("Unknown error cleaning up reader for '{}'", topic_name);
199→  }
200→}
