588→BridgeServer::StatsSnapshot BridgeServer::snapshot_and_reset_stats() {
589→  std::lock_guard<std::mutex> lock(stats_mutex_);
590→  StatsSnapshot snapshot;
591→  snapshot.topic_receive_counts = std::move(topic_receive_counts_);
592→  topic_receive_counts_.clear();
593→  snapshot.topic_forward_counts = std::move(topic_forward_counts_);
594→  topic_forward_counts_.clear();
595→  snapshot.publish_cycles = publish_cycles_;
596→  publish_cycles_ = 0;
597→  snapshot.total_bytes_published = total_bytes_published_;
598→  return snapshot;
