600→
601→void BridgeServer::publish_aggregated_messages() {
602→  if (!initialized_) {
603→    return;
604→  }
605→
606→  std::unordered_map<std::string, std::deque<BufferedMessage>> messages;
607→  message_buffer_->move_messages(messages);
608→
609→  if (messages.empty()) {
610→    return;
611→  }
612→
613→  try {
614→    auto active_sessions = session_manager_->get_active_sessions();
615→    if (active_sessions.empty()) {
616→      return;
617→    }
618→
619→    // Group clients by subscription config (topic + rate) to avoid redundant serialization.
620→    using GroupKey = std::map<std::string, int>;
621→    std::map<GroupKey, std::vector<std::string>> subscription_groups;
622→    std::unordered_map<std::string, std::unordered_map<std::string, double>> client_subs;
623→
624→    for (const auto& client_id : active_sessions) {
625→      auto subs = session_manager_->get_subscriptions(client_id);
626→      if (subs.empty()) {
627→        continue;
628→      }
629→      GroupKey key;
630→      for (const auto& [topic, rate_hz] : subs) {
631→        key[topic] = static_cast<int>(rate_hz * 1000);
632→      }
633→      subscription_groups[key].push_back(client_id);
634→      client_subs[client_id] = std::move(subs);
635→    }
636→
637→    size_t total_msg_count = 0;
638→    size_t total_bytes = 0;
639→    std::unordered_map<std::string, uint64_t> forward_counts;
640→
641→    // Collect paused state outside of last_sent_mutex_ to avoid lock ordering issues.
642→    std::unordered_map<std::string, bool> paused_state;
643→    for (const auto& [group_key, client_ids] : subscription_groups) {
644→      for (const auto& client_id : client_ids) {
645→        paused_state[client_id] = session_manager_->is_paused(client_id);
646→      }
647→    }
648→
649→    // Per-group serialized frames, built under last_sent_mutex_ for rate limiting
650→    struct GroupFrame {
651→      std::vector<uint8_t> compressed_data;
652→      size_t msg_count;
653→      std::vector<std::string> client_ids;
654→    };
655→    std::vector<GroupFrame> frames;
656→
657→    {
658→      std::lock_guard<std::mutex> sent_lock(last_sent_mutex_);
659→
660→      for (const auto& [group_key, client_ids] : subscription_groups) {
661→        AggregatedMessageSerializer serializer;
662→        size_t group_msg_count = 0;
663→
664→        const auto& representative_subs = client_subs[client_ids.front()];
665→        auto& rep_last_sent = last_sent_times_[client_ids.front()];
666→
667→        for (const auto& [topic, msgs] : messages) {
668→          auto sub_it = representative_subs.find(topic);
669→          if (sub_it == representative_subs.end()) {
670→            continue;
671→          }
672→
673→          double rate_hz = sub_it->second;
674→          int rate_mhz = static_cast<int>(rate_hz * 1000);
675→
676→          if (rate_mhz == 0) {
677→            for (const auto& msg : msgs) {
678→              serializer.serialize_message(topic, msg.timestamp_ns, msg.data->data(), msg.data->size());
679→              group_msg_count++;
680→              forward_counts[topic]++;
681→            }
682→          } else {
683→            uint64_t min_interval_ns = static_cast<uint64_t>(1'000'000'000'000) / static_cast<uint64_t>(rate_mhz);
684→            uint64_t last_sent = rep_last_sent[topic];
685→
686→            for (const auto& msg : msgs) {
687→              if (msg.timestamp_ns >= last_sent + min_interval_ns) {
688→                serializer.serialize_message(topic, msg.timestamp_ns, msg.data->data(), msg.data->size());
689→                last_sent = msg.timestamp_ns;
690→                group_msg_count++;
691→                forward_counts[topic]++;
692→              }
693→            }
694→            rep_last_sent[topic] = last_sent;
695→          }
696→        }
697→
698→        if (group_msg_count == 0) {
699→          continue;
700→        }
701→
702→        GroupFrame frame;
703→        frame.compressed_data = serializer.finalize();
704→        frame.msg_count = group_msg_count;
705→        frame.client_ids = client_ids;
706→
707→        // Propagate rate-limiting state to other clients in the group
708→        for (const auto& client_id : client_ids) {
709→          if (client_id != client_ids.front()) {
710→            last_sent_times_[client_id] = rep_last_sent;
711→          }
712→        }
713→
714→        frames.push_back(std::move(frame));
715→      }
716→    }  // last_sent_mutex_ released here
717→
718→    // Send frames outside of any lock
719→    for (const auto& frame : frames) {
720→      bool any_sent = false;
721→      for (const auto& client_id : frame.client_ids) {
722→        auto it = paused_state.find(client_id);
723→        if (it != paused_state.end() && it->second) {
724→          continue;
725→        }
726→        if (middleware_->send_binary(client_id, frame.compressed_data)) {
727→          any_sent = true;
728→        } else {
729→          spdlog::debug("Failed to send binary frame to client '{}'", client_id);
730→        }
731→      }
732→
733→      if (any_sent) {
734→        total_msg_count += frame.msg_count;
735→        total_bytes += frame.compressed_data.size();
736→      }
737→    }
738→
739→    if (total_msg_count > 0) {
740→      std::lock_guard<std::mutex> lock(stats_mutex_);
741→      total_messages_published_ += total_msg_count;
742→      total_bytes_published_ += total_bytes;
743→      publish_cycles_++;
744→      for (const auto& [topic, count] : forward_counts) {
745→        topic_forward_counts_[topic] += count;
746→      }
747→    }
748→  } catch (const std::exception& e) {
749→    spdlog::error("Error publishing aggregated messages: {}", e.what());
750→  }
751→}
