 20→#include "pj_bridge/standalone_event_loop.hpp"
 21→
 22→#include <spdlog/spdlog.h>
 23→
 24→#include <atomic>
 25→#include <chrono>
 26→#include <csignal>
 27→#include <thread>
 28→
 29→namespace pj_bridge {
 30→
 31→namespace {
 32→std::atomic<bool> g_shutdown{false};
 33→
 34→void signal_handler(int /*signum*/) {
 35→  g_shutdown.store(true);
 36→}
 37→}  // namespace
 38→
 39→void run_standalone_event_loop(
 40→    BridgeServer& server, std::shared_ptr<SubscriptionManagerInterface> sub_manager,
 41→    std::shared_ptr<WebSocketMiddleware> middleware, const StandaloneConfig& config) {
 42→  std::signal(SIGINT, signal_handler);
 43→  std::signal(SIGTERM, signal_handler);
 44→
 45→  if (!server.initialize()) {
 46→    spdlog::error("Failed to initialize bridge server");
 47→    return;
 48→  }
 49→
 50→  spdlog::info("Bridge server initialized, entering event loop");
 51→
 52→  using clock = std::chrono::steady_clock;
 53→  auto publish_interval =
 54→      std::chrono::duration_cast<std::chrono::nanoseconds>(std::chrono::duration<double>(1.0 / config.publish_rate));
 55→  auto last_publish = clock::now();
 56→  auto last_timeout_check = clock::now();
 57→  auto last_stats_print = clock::now();
 58→  uint64_t prev_bytes_published = 0;
 59→
 60→  while (!g_shutdown.load()) {
 61→    server.process_requests();
 62→
 63→    auto now = clock::now();
 64→
 65→    if (now - last_publish >= publish_interval) {
 66→      server.publish_aggregated_messages();
 67→      last_publish += publish_interval;
 68→    }
 69→
 70→    if (now - last_timeout_check >= std::chrono::seconds(1)) {
 71→      server.check_session_timeouts();
 72→      last_timeout_check = now;
 73→    }
 74→
 75→    if (config.stats_enabled && now - last_stats_print >= std::chrono::seconds(5)) {
 76→      auto elapsed = std::chrono::duration<double>(now - last_stats_print).count();
 77→      auto snapshot = server.snapshot_and_reset_stats();
 78→
 79→      std::string stats_msg = "=== Stats ===\n  DDS receive rates:";
 80→      if (snapshot.topic_receive_counts.empty()) {
 81→        stats_msg += "\n    (no subscriptions)";
 82→      } else {
 83→        for (const auto& [topic, count] : snapshot.topic_receive_counts) {
 84→          stats_msg += fmt::format("\n    {}: {:.1f} msg/s", topic, static_cast<double>(count) / elapsed);
 85→        }
 86→      }
 87→
 88→      stats_msg +=
 89→          fmt::format("\n  Publish frequency: {:.1f} Hz", static_cast<double>(snapshot.publish_cycles) / elapsed);
 90→      uint64_t delta_bytes = snapshot.total_bytes_published - prev_bytes_published;
 91→      prev_bytes_published = snapshot.total_bytes_published;
 92→      stats_msg += fmt::format("\n  Sent: {:.2f} MB/s", static_cast<double>(delta_bytes) / elapsed / (1024.0 * 1024.0));
 93→
 94→      spdlog::info(stats_msg);
 95→      last_stats_print = now;
 96→    }
 97→
 98→    std::this_thread::sleep_for(std::chrono::milliseconds(1));
 99→  }
100→
101→  spdlog::info("Shutting down...");
102→
103→  // Explicit ordered shutdown to avoid use-after-free:
104→  // 1. Clear DDS message callback
105→  spdlog::debug("[shutdown] Clearing DDS message callback...");
106→  sub_manager->set_message_callback(nullptr);
107→  // 2. Unsubscribe all DDS readers
108→  spdlog::debug("[shutdown] Unsubscribing all DDS readers...");
109→  sub_manager->unsubscribe_all();
110→  // 3. Shutdown WebSocket server
111→  spdlog::debug("[shutdown] Shutting down WebSocket middleware...");
112→  middleware->shutdown();
113→  spdlog::debug("[shutdown] Cleanup complete, exiting scope (destructors will run)...");
114→}
