520→void BridgeServer::inject_response_fields(nlohmann::json& response, const nlohmann::json& request) const {
521→  response["protocol_version"] = kProtocolVersion;
522→  if (request.contains("id") && request["id"].is_string()) {
523→    response["id"] = request["id"];
524→  }
525→}
