538→void BridgeServer::check_session_timeouts() {
539→  if (!initialized_) {
540→    return;
541→  }
542→
543→  auto timed_out_sessions = session_manager_->get_timed_out_sessions();
544→
545→  for (const auto& client_id : timed_out_sessions) {
546→    spdlog::warn("Session timeout for client '{}'", client_id);
547→    cleanup_session(client_id);
548→  }
