551→void BridgeServer::cleanup_session(const std::string& client_id) {
552→  std::lock_guard<std::mutex> lock(cleanup_mutex_);
553→
554→  if (!session_manager_->session_exists(client_id)) {
555→    return;
556→  }
557→
558→  auto subscriptions = session_manager_->get_subscriptions(client_id);
559→  bool was_paused = session_manager_->is_paused(client_id);
560→
561→  // Unsubscribe from all topics (only if not paused — paused clients already decremented ref counts)
562→  if (!was_paused) {
563→    for (const auto& [topic, rate] : subscriptions) {
564→      subscription_manager_->unsubscribe(topic);
565→      spdlog::debug("Unsubscribed client '{}' from topic '{}'", client_id, topic);
566→    }
567→  }
568→
569→  session_manager_->remove_session(client_id);
570→
571→  {
572→    std::lock_guard<std::mutex> sent_lock(last_sent_mutex_);
573→    last_sent_times_.erase(client_id);
574→  }
575→
576→  spdlog::info("Cleaned up session for client '{}' ({} topics unsubscribed)", client_id, subscriptions.size());
577→}
