 39→// ---------------------------------------------------------------------------
 40→// InternalReaderListener
 41→// ---------------------------------------------------------------------------
 42→class FastDdsSubscriptionManager::InternalReaderListener : public DataReaderListener {
 43→ public:
 44→  InternalReaderListener(
 45→      const std::string& topic_name, FastDdsSubscriptionManager& manager, DynamicType::_ref_type dynamic_type)
 46→      : topic_name_(topic_name), manager_(manager), dynamic_type_(dynamic_type), pub_sub_type_(dynamic_type) {}
 47→
 48→  void on_data_available(DataReader* reader) override {
 49→    try {
 50→      MessageCallback cb;
 51→      {
 52→        std::lock_guard<std::mutex> lock(manager_.mutex_);
 53→        cb = manager_.callback_;
 54→      }
 55→
 56→      if (!cb) {
 57→        return;
 58→      }
 59→
 60→      DynamicData::_ref_type data = DynamicDataFactory::get_instance()->create_data(dynamic_type_);
 61→      SampleInfo info;
 62→
 63→      while (RETCODE_OK == reader->take_next_sample(&data, &info)) {
 64→        if (!info.valid_data) {
 65→          continue;
 66→        }
 67→
 68→        // Re-serialize DynamicData to get raw CDR bytes
 69→        uint32_t size =
 70→            pub_sub_type_.calculate_serialized_size(&data, DataRepresentationId_t::XCDR2_DATA_REPRESENTATION);
 71→        SerializedPayload_t payload(size);
 72→        if (!pub_sub_type_.serialize(&data, payload, DataRepresentationId_t::XCDR2_DATA_REPRESENTATION)) {
 73→          spdlog::warn("Failed to serialize DynamicData for '{}'", topic_name_);
 74→          continue;
 75→        }
 76→
 77→        auto cdr_data = std::make_shared<std::vector<std::byte>>(payload.length);
 78→        std::memcpy(cdr_data->data(), payload.data, payload.length);
 79→
 80→        uint64_t timestamp_ns =
 81→            static_cast<uint64_t>(info.source_timestamp.seconds()) * 1'000'000'000ULL + info.source_timestamp.nanosec();
 82→
 83→        cb(topic_name_, std::move(cdr_data), timestamp_ns);
 84→      }
 85→    } catch (const std::exception& e) {
 86→      spdlog::error("Exception in DataReaderListener for '{}': {}", topic_name_, e.what());
 87→    }
 88→  }
 89→
 90→ private:
 91→  std::string topic_name_;
 92→  FastDdsSubscriptionManager& manager_;
 93→  DynamicType::_ref_type dynamic_type_;
 94→  DynamicPubSubType pub_sub_type_;
 95→};
 96→
 97→// ---------------------------------------------------------------------------
 98→// FastDdsSubscriptionManager
 99→// ---------------------------------------------------------------------------
100→FastDdsSubscriptionManager::FastDdsSubscriptionManager(FastDdsTopicSource& topic_source)
101→    : topic_source_(topic_source) {}
102→
103→FastDdsSubscriptionManager::~FastDdsSubscriptionManager() {
104→  unsubscribe_all();
105→}
