107→void FastDdsSubscriptionManager::set_message_callback(MessageCallback callback) {
108→  std::lock_guard<std::mutex> lock(mutex_);
109→  callback_ = std::move(callback);
110→}
111→
112→bool FastDdsSubscriptionManager::subscribe(const std::string& topic_name, const std::string& /*topic_type*/) {
113→  std::lock_guard<std::mutex> lock(mutex_);
114→
115→  auto it = subscriptions_.find(topic_name);
116→  if (it != subscriptions_.end()) {
117→    it->second.reference_count++;
118→    spdlog::debug("Incremented ref count for '{}' to {}", topic_name, it->second.reference_count);
119→    return true;
120→  }
121→
122→  auto dynamic_type = topic_source_.get_dynamic_type(topic_name);
123→  if (!dynamic_type) {
124→    spdlog::error("Topic '{}' not found in discovery", topic_name);
125→    return false;
126→  }
127→
128→  auto domain_id_opt = topic_source_.get_domain_id(topic_name);
129→  if (!domain_id_opt) {
130→    spdlog::error("No domain ID for topic '{}'", topic_name);
131→    return false;
132→  }
133→
134→  auto* participant = topic_source_.get_participant(*domain_id_opt);
135→  if (!participant) {
136→    spdlog::error("No participant for domain {}", *domain_id_opt);
137→    return false;
138→  }
139→
140→  try {
141→    // Register the DynamicType with the participant
142→    TypeSupport type_support(new DynamicPubSubType(dynamic_type));
143→    type_support.register_type(participant);
144→
145→    // Create Topic
146→    Topic* topic = participant->create_topic(topic_name, type_support.get_type_name(), TOPIC_QOS_DEFAULT);
147→    if (!topic) {
148→      spdlog::error("Failed to create topic for '{}'", topic_name);
149→      return false;
150→    }
151→
152→    // Create Subscriber
153→    Subscriber* subscriber = participant->create_subscriber(SUBSCRIBER_QOS_DEFAULT);
154→    if (!subscriber) {
155→      participant->delete_topic(topic);
156→      spdlog::error("Failed to create subscriber for '{}'", topic_name);
157→      return false;
158→    }
159→
160→    // Create DataReader with listener
161→    auto listener = std::make_shared<InternalReaderListener>(topic_name, *this, dynamic_type);
162→    DataReader* reader = subscriber->create_datareader(topic, DATAREADER_QOS_DEFAULT, listener.get());
163→    if (!reader) {
164→      participant->delete_subscriber(subscriber);
165→      participant->delete_topic(topic);
166→      spdlog::error("Failed to create datareader for '{}'", topic_name);
167→      return false;
168→    }
169→
170→    subscriptions_.emplace(topic_name, SubscriptionInfo{participant, subscriber, topic, reader, listener, 1});
171→
172→    spdlog::info(
173→        "Subscribed to '{}' (type: '{}', domain: {})", topic_name, type_support.get_type_name(), *domain_id_opt);
174→    return true;
175→  } catch (const std::exception& e) {
176→    spdlog::error("Failed to subscribe to '{}': {}", topic_name, e.what());
177→    return false;
178→  }
179→}
180→
181→bool FastDdsSubscriptionManager::unsubscribe(const std::string& topic_name) {
182→  std::optional<SubscriptionInfo> to_close;
183→
184→  {
185→    std::lock_guard<std::mutex> lock(mutex_);
186→
187→    auto it = subscriptions_.find(topic_name);
188→    if (it == subscriptions_.end()) {
189→      return false;
190→    }
191→
192→    if (it->second.reference_count == 0) {
193→      return false;
194→    }
195→
196→    it->second.reference_count--;
197→    spdlog::debug("Decremented ref count for '{}' to {}", topic_name, it->second.reference_count);
198→
199→    if (it->second.reference_count == 0) {
200→      to_close.emplace(std::move(it->second));
201→      subscriptions_.erase(it);
202→    }
203→  }
204→
205→  if (to_close) {
206→    close_subscription(topic_name, *to_close);
207→    spdlog::info("Unsubscribed from '{}' (reader destroyed)", topic_name);
208→  }
209→
210→  return true;
211→}
212→
213→void FastDdsSubscriptionManager::unsubscribe_all() {
214→  std::unordered_map<std::string, SubscriptionInfo> to_close;
215→
216→  {
217→    std::lock_guard<std::mutex> lock(mutex_);
218→    to_close.swap(subscriptions_);
219→  }
220→
221→  spdlog::debug("[shutdown] unsubscribe_all: {} subscriptions to close", to_close.size());
222→  for (auto& [name, info] : to_close) {
223→    spdlog::debug("[shutdown] Closing reader for '{}'...", name);
224→    close_subscription(name, info);
225→    spdlog::debug("[shutdown] Closed '{}'", name);
226→  }
227→  spdlog::debug("[shutdown] unsubscribe_all complete");
228→}
229→
230→void FastDdsSubscriptionManager::close_subscription(const std::string& topic_name, SubscriptionInfo& info) {
231→  try {
232→    info.reader->set_listener(nullptr);
233→    info.subscriber->delete_datareader(info.reader);
234→    info.participant->delete_subscriber(info.subscriber);
235→    info.participant->delete_topic(info.topic);
236→  } catch (const std::exception& e) {
237→    spdlog::warn("Error cleaning up reader for '{}': {}", topic_name, e.what());
238→  } catch (...) {
239→    spdlog::warn("Unknown error cleaning up reader for '{}'", topic_name);
240→  }
241→}
