 40→// ---------------------------------------------------------------------------
 41→// ParticipantListener — handles on_data_writer_discovery callbacks
 42→// ---------------------------------------------------------------------------
 43→class FastDdsTopicSource::ParticipantListener : public DomainParticipantListener {
 44→ public:
 45→  ParticipantListener(FastDdsTopicSource& source, int32_t domain_id) : source_(source), domain_id_(domain_id) {}
 46→
 47→  void on_data_writer_discovery(
 48→      DomainParticipant* /*participant*/, WriterDiscoveryStatus reason, const PublicationBuiltinTopicData& info,
 49→      bool& should_be_ignored) override {
 50→    should_be_ignored = false;
 51→
 52→    if (reason != WriterDiscoveryStatus::DISCOVERED_WRITER) {
 53→      return;
 54→    }
 55→
 56→    try {
 57→      std::string topic_name(info.topic_name);
 58→
 59→      // Skip if already cached (fast check before heavy TypeObject work)
 60→      {
 61→        std::shared_lock<std::shared_mutex> lock(source_.mutex_);
 62→        if (source_.topics_.count(topic_name) > 0) {
 63→          return;
 64→        }
 65→      }
 66→
 67→      // Get TypeObject from the global registry via the type identifier in the
 68→      // discovery info's TypeInformation
 69→      xtypes::TypeObject type_object;
 70→      auto& registry = DomainParticipantFactory::get_instance()->type_object_registry();
 71→      const auto& type_id = info.type_information.type_information.complete().typeid_with_size().type_id();
 72→
 73→      if (RETCODE_OK != registry.get_type_object(type_id, type_object)) {
 74→        spdlog::debug("Topic '{}' discovered but TypeObject not yet in registry (domain {})", topic_name, domain_id_);
 75→        return;
 76→      }
 77→
 78→      // Build DynamicType
 79→      auto builder = DynamicTypeBuilderFactory::get_instance()->create_type_w_type_object(type_object);
 80→      if (!builder) {
 81→        spdlog::warn("Failed to create DynamicTypeBuilder for '{}' (domain {})", topic_name, domain_id_);
 82→        return;
 83→      }
 84→      DynamicType::_ref_type dynamic_type = builder->build();
 85→      if (!dynamic_type) {
 86→        spdlog::warn("Failed to build DynamicType for '{}' (domain {})", topic_name, domain_id_);
 87→        return;
 88→      }
 89→
 90→      // Only accept struct types (like RTI backend)
 91→      if (dynamic_type->get_kind() != TK_STRUCTURE) {
 92→        spdlog::debug(
 93→            "Topic '{}' has non-struct type '{}', skipping", topic_name, std::string(dynamic_type->get_name()));
 94→        return;
 95→      }
 96→
 97→      // Generate OMG IDL schema
 98→      std::ostringstream oss;
 99→      if (RETCODE_OK != idl_serialize(dynamic_type, oss)) {
100→        spdlog::warn("Failed to serialize IDL for '{}' (domain {})", topic_name, domain_id_);
101→        return;
102→      }
103→
104→      spdlog::info(
105→          "Discovered topic '{}' (type: '{}') in domain {}", topic_name, std::string(dynamic_type->get_name()),
106→          domain_id_);
107→
108→      source_.on_topic_discovered(topic_name, dynamic_type, oss.str(), domain_id_);
109→
110→    } catch (const std::exception& e) {
111→      spdlog::error("Exception in ParticipantListener on domain {}: {}", domain_id_, e.what());
112→    }
113→  }
114→
115→ private:
116→  FastDdsTopicSource& source_;
117→  int32_t domain_id_;
118→};
