121→// FastDdsTopicSource
122→// ---------------------------------------------------------------------------
123→FastDdsTopicSource::FastDdsTopicSource(const std::vector<int32_t>& domain_ids) {
124→  auto* factory = DomainParticipantFactory::get_instance();
125→
126→  for (int32_t domain_id : domain_ids) {
127→    spdlog::info("Creating DomainParticipant for domain {}", domain_id);
128→
129→    DomainParticipantQos pqos;
130→    pqos.name("pj_bridge_fastdds_" + std::to_string(domain_id));
131→    // TypeLookup service is enabled by default in Fast DDS 3.4
132→
133→    auto listener = std::make_shared<ParticipantListener>(*this, domain_id);
134→    listeners_.push_back(listener);
135→
136→    DomainParticipant* participant = factory->create_participant(domain_id, pqos, listener.get(), StatusMask::none());
137→
138→    if (!participant) {
139→      spdlog::error("Failed to create DomainParticipant for domain {}", domain_id);
140→      continue;
141→    }
142→
143→    participants_.emplace(domain_id, participant);
144→    spdlog::info("Topic discovery active on domain {}", domain_id);
145→  }
146→}
147→
148→FastDdsTopicSource::~FastDdsTopicSource() {
149→  auto* factory = DomainParticipantFactory::get_instance();
150→
151→  for (auto& [domain_id, participant] : participants_) {
152→    try {
153→      spdlog::debug("[shutdown] Deleting DomainParticipant for domain {}...", domain_id);
154→      // Remove listener before deletion to prevent callbacks during teardown
155→      participant->set_listener(nullptr);
156→      factory->delete_participant(participant);
157→      spdlog::debug("[shutdown] DomainParticipant for domain {} deleted", domain_id);
158→    } catch (const std::exception& e) {
159→      spdlog::warn("Error deleting participant for domain {}: {}", domain_id, e.what());
160→    } catch (...) {
161→      spdlog::warn("Unknown error deleting participant for domain {}", domain_id);
162→    }
163→  }
164→  listeners_.clear();
165→  spdlog::debug("[shutdown] ~FastDdsTopicSource complete");
166→}
