168→void FastDdsTopicSource::on_topic_discovered(
169→    const std::string& topic_name, DynamicType::_ref_type dynamic_type, const std::string& schema_idl,
170→    int32_t domain_id) {
171→  std::unique_lock<std::shared_mutex> lock(mutex_);
172→
173→  if (topics_.find(topic_name) != topics_.end()) {
174→    return;
175→  }
176→
177→  topics_.emplace(topic_name, DiscoveredTopic{dynamic_type, schema_idl, domain_id});
178→  spdlog::info(
179→      "Cached topic '{}' (type: '{}', domain: {})", topic_name, std::string(dynamic_type->get_name()), domain_id);
180→}
