182→std::vector<TopicInfo> FastDdsTopicSource::get_topics() {
183→  std::shared_lock<std::shared_mutex> lock(mutex_);
184→
185→  std::vector<TopicInfo> result;
186→  result.reserve(topics_.size());
187→
188→  for (const auto& [name, topic] : topics_) {
189→    result.push_back({name, std::string(topic.dynamic_type->get_name())});
190→  }
191→
192→  return result;
193→}
