54→  bool set_paused(const std::string& client_id, bool paused);
55→  bool is_paused(const std::string& client_id) const;
56→
57→ private:
58→  std::unordered_map<std::string, Session> sessions_;
59→  mutable std::mutex mutex_;
60→  std::chrono::duration<double> timeout_duration_;
61→};
