 93→bool SessionManager::remove_subscription(const std::string& client_id, const std::string& topic) {
 94→  std::lock_guard<std::mutex> lock(mutex_);
 95→
 96→  auto it = sessions_.find(client_id);
 97→  if (it == sessions_.end()) {
 98→    return false;
 99→  }
100→
