104→std::unordered_map<std::string, double> SessionManager::get_subscriptions(const std::string& client_id) const {
105→  std::lock_guard<std::mutex> lock(mutex_);
106→
107→  auto it = sessions_.find(client_id);
108→  if (it == sessions_.end()) {
109→    return {};
110→  }
111→
112→  return it->second.subscribed_topics;
