 83→        cb(client_id);
 84→      }
 85→
 86→      {
 87→        std::lock_guard<std::mutex> clients_lock(clients_mutex_);
 88→        clients_.erase(client_id);
 89→      }
 90→
 91→    } else if (msg->type == ix::WebSocketMessageType::Message) {
 92→      if (!msg->binary) {
 93→        IncomingRequest req;
 94→        req.client_id = client_id;
 95→        req.data.assign(msg->str.begin(), msg->str.end());
 96→
 97→        {
 98→          std::lock_guard<std::mutex> queue_lock(queue_mutex_);
 99→          if (incoming_queue_.size() >= kMaxIncomingQueueSize) {
100→            spdlog::warn(
101→                "Incoming queue full ({} messages), dropping message from client '{}'", kMaxIncomingQueueSize,
102→                client_id);
103→            return;
104→          }
105→          incoming_queue_.push(std::move(req));
106→        }
107→        queue_cv_.notify_one();
108→      }
109→    }
110→  });
111→
112→  auto listen_result = server_->listen();
113→  if (!listen_result.first) {
114→    server_.reset();
115→    return tl::unexpected<std::string>(
116→        "Failed to listen on port " + std::to_string(port) + ": " + listen_result.second);
117→  }
118→
119→  server_->start();
120→  initialized_ = true;
121→
122→  return {};
123→}
124→
125→void WebSocketMiddleware::shutdown() {
126→  std::shared_ptr<ix::WebSocketServer> server_to_stop;
127→
128→  {
129→    std::lock_guard<std::mutex> lock(state_mutex_);
130→
131→    if (!initialized_) {
132→      return;
133→    }
134→
135→    initialized_ = false;
136→    on_connect_ = nullptr;
137→    on_disconnect_ = nullptr;
138→    server_to_stop = std::move(server_);
139→  }
140→
141→  queue_cv_.notify_all();
142→
143→  if (server_to_stop) {
144→    // Replace the message callback with a no-op before stopping. The original
145→    // callback captures `this`, so it must not fire after the WebSocketMiddleware
146→    // instance is destroyed (which can happen if the stop thread is detached on timeout).
147→    server_to_stop->setOnClientMessageCallback(
148→        [](std::shared_ptr<ix::ConnectionState>, ix::WebSocket&, const ix::WebSocketMessagePtr&) {});
149→
150→    // Initiate graceful close on all connected clients before calling stop().
151→    spdlog::debug("[shutdown] Pre-closing {} WebSocket client(s)...", server_to_stop->getClients().size());
152→    for (const auto& client : server_to_stop->getClients()) {
153→      client->close();
154→    }
155→
156→    // Run stop() on a dedicated thread with a timeout.
157→    spdlog::debug("[shutdown] Starting server stop thread...");
158→    auto done = std::make_shared<std::atomic<bool>>(false);
159→    std::thread stop_thread([server_to_stop, done]() {
160→      server_to_stop->stop();
161→      done->store(true);
162→    });
163→
164→    auto start = std::chrono::steady_clock::now();
165→    auto deadline = start + std::chrono::seconds(kShutdownTimeoutSeconds);
166→    while (!done->load() && std::chrono::steady_clock::now() < deadline) {
167→      std::this_thread::sleep_for(std::chrono::milliseconds(50));
168→    }
169→    auto elapsed_ms =
170→        std::chrono::duration_cast<std::chrono::milliseconds>(std::chrono::steady_clock::now() - start).count();
171→
172→    if (done->load()) {
173→      stop_thread.join();
174→      spdlog::debug("[shutdown] Server stop completed (took {}ms)", elapsed_ms);
175→    } else {
176→      // Timeout reached. Detach the thread and let it finish in the background.
177→      // The thread captures server_to_stop by shared_ptr, so the server
178→      // will be destroyed when stop() finishes and the thread exits.
179→      // The message callback was already cleared above, so no use-after-free.
180→      spdlog::warn(
181→          "[shutdown] Server stop timed out after {}s ({}ms elapsed), detaching shutdown thread",
182→          kShutdownTimeoutSeconds, elapsed_ms);
183→      stop_thread.detach();
184→    }
185→  }
186→
187→  {
188→    std::lock_guard<std::mutex> clients_lock(clients_mutex_);
189→    clients_.clear();
190→  }
191→
192→  {
193→    std::lock_guard<std::mutex> queue_lock(queue_mutex_);
194→    std::queue<IncomingRequest> empty;
195→    std::swap(incoming_queue_, empty);
196→  }
197→}
