239→  std::shared_ptr<ix::WebSocket> ws;
240→  {
241→    std::lock_guard<std::mutex> lock(clients_mutex_);
242→    auto it = clients_.find(client_identity);
243→    if (it == clients_.end() || !it->second) {
244→      return false;
245→    }
246→    ws = it->second;
247→  }
248→
249→  std::string binary_data(reinterpret_cast<const char*>(data.data()), data.size());
