254→bool WebSocketMiddleware::publish_data(const std::vector<uint8_t>& data) {
255→  std::vector<std::shared_ptr<ix::WebSocket>> clients_copy;
256→  {
257→    std::lock_guard<std::mutex> lock(clients_mutex_);
258→    if (clients_.empty()) {
259→      return false;
260→    }
261→    clients_copy.reserve(clients_.size());
262→    for (const auto& [client_id, ws] : clients_) {
263→      if (ws) {
264→        clients_copy.push_back(ws);
265→      }
266→    }
267→  }
268→
269→  std::string binary_data(reinterpret_cast<const char*>(data.data()), data.size());
270→  bool any_sent = false;
271→
272→  for (const auto& ws : clients_copy) {
273→    auto send_info = ws->sendBinary(binary_data);
274→    if (send_info.success) {
275→      any_sent = true;
276→    }
277→  }
278→
279→  return any_sent;
280→}
