      payload_.length = 0;
      if (!pub_sub_type_.serialize(&data_, payload_, DataRepresentationId_t::XCDR2_DATA_REPRESENTATION)) {
        spdlog::warn("Failed to serialize DynamicData for '{}'", topic_name_);
        continue;
