    }

    spdlog::info("Subscribed to '{}' (type: '{}', domain: {})", topic_name, struct_type.name(), *domain_id_opt);
    return true;
  } catch (const std::exception& e) {
    spdlog::error("Failed to subscribe to '{}': {}", topic_name, e.what());
    return false;
  }
}

